    17→// Helper to check if an item is a DashboardGroup
    18→function isDashboardGroup(item: unknown): item is DashboardGroup {
    19→  return (
    20→    typeof item === "object" &&
    21→    item !== null &&
    22→    "title" in item &&
    23→    "charts" in item &&
    24→    Array.isArray((item as { charts: unknown }).charts)
    25→  );
    26→}
    27→
    28→// Generate default layouts from dashboard panels
    29→function generateDefaultLayouts(dashboard: Dashboard): ResponsiveLayouts {
    30→  const allPanels: PanelDescriptor[] = [];
    31→  dashboard.charts.forEach((item) => {
    32→    if (isDashboardGroup(item)) {
    33→      allPanels.push(...item.charts);
    34→    } else {
    35→      allPanels.push(item);
    36→    }
    37→  });
    38→
    39→  const lg: LayoutItem[] = [];
    40→  const md: LayoutItem[] = [];
    41→  const sm: LayoutItem[] = [];
    42→
    43→  allPanels.forEach((panel, index) => {
    44→    const gridPos = panel.gridPos ?? { w: 24, h: 6 };
    45→    const constraints = getPanelConstraints(panel.type);
    46→    const key = `panel-${index}`;
    47→
    48→    lg.push({
    49→      i: key,
    50→      x: gridPos.x ?? (index * 6) % 24,
    51→      y: gridPos.y ?? Math.floor((index * 6) / 24) * 4,
    52→      w: gridPos.w,
    53→      h: gridPos.h,
    54→      ...constraints,
    55→    });
    56→
    57→    const mdW = Math.max(constraints.minW, Math.round((gridPos.w / 24) * 6));
    58→    md.push({
    59→      i: key,
    60→      x: (index * 3) % 6,
    61→      y: Math.floor((index * 3) / 6) * 4,
    62→      w: Math.min(mdW, 6),
    63→      h: gridPos.h,
    64→      minW: Math.min(constraints.minW, 6),
    65→      minH: constraints.minH,
    66→      maxW: 6,
    67→      maxH: constraints.maxH,
    68→    });
    69→
    70→    sm.push({
    71→      i: key,
    72→      x: 0,
    73→      y: index * 4,
    74→      w: 1,
    75→      h: gridPos.h,
    76→      minW: 1,
    77→      minH: constraints.minH,
    78→      maxW: 1,
    79→      maxH: constraints.maxH,
    80→      static: true,
    81→    });
    82→  });
    83→
    84→  return { lg, md, sm };
    85→}
    86→
    87→export interface DashboardPageRef {
    88→  setSelectedTimeSpan: (timeSpan: TimeSpan) => void;
    89→  setFilter: (filterName: string, value: string) => void;
    90→}
    91→
    92→interface DashboardPageProps {
    93→  panels: Dashboard;
    94→  filterSpecs?: FilterSpec[];
    95→  showInputFilter?: boolean;
    96→  headerActions?: React.ReactNode;
    97→  timezone?: string;
    98→  showTimeSpanSelector?: boolean;
    99→  showRefresh?: boolean;
   100→  showAutoRefresh?: boolean;
   101→  chartSelectionFilterName?: string;
   102→  /**
   103→   * Unique identifier for this dashboard (used for layout persistence).
   104→   * If not provided, layout won't be persisted.
   105→   */
   106→  dashboardId?: string;
   107→  /**
   108→   * Children to render below the dashboard panels.
   109→   * Children can use the useDashboardRefresh hook to register
   110→   * themselves for automatic refresh when the dashboard refreshes.
   111→   */
   112→  children?: React.ReactNode;
   113→}
   114→
   115→// Inner component to access layout context
   116→interface DashboardFilterWithResetProps {
   117→  filterRef: React.RefObject<DashboardFilterComponent | null>;
   118→  filterSpecs: FilterSpec[];
   119→  onFilterChange?: (filter: SelectedFilter) => void;
   120→  onTimeSpanChange?: (timeSpan: TimeSpan) => void;
   121→  onLoadSourceData?: (query: SQLQuery) => Promise<string[]>;
   122→  timezone?: string;
   123→  showTimeSpanSelector?: boolean;
   124→  showRefresh?: boolean;
   125→  showAutoRefresh?: boolean;
   126→  headerActions?: React.ReactNode;
   127→}
   128→
   129→function DashboardFilterWithReset({
   130→  filterRef,
   131→  filterSpecs,
   132→  onFilterChange,
   133→  onTimeSpanChange,
   134→  onLoadSourceData,
   135→  timezone,
   136→  showTimeSpanSelector,
   137→  showRefresh,
   138→  showAutoRefresh,
   139→  headerActions,
   140→}: DashboardFilterWithResetProps) {
   141→  const { resetLayout } = useDashboardLayout();
   142→
   143→  return (
   144→    <DashboardFilterComponent
   145→      ref={filterRef}
   146→      filterSpecs={filterSpecs}
   147→      onFilterChange={onFilterChange}
   148→      onTimeSpanChange={onTimeSpanChange}
   149→      onLoadSourceData={onLoadSourceData}
   150→      timezone={timezone}
   151→      showTimeSpanSelector={showTimeSpanSelector}
   152→      showRefresh={showRefresh}
   153→      showAutoRefresh={showAutoRefresh}
   154→      onResetLayout={resetLayout}
   155→    >
   156→      {headerActions}
   157→    </DashboardFilterComponent>
   158→  );
   159→}
   160→
   161→const DashboardPage = forwardRef<DashboardPageRef, DashboardPageProps>(
   162→  (
   163→    {
   164→      panels,
   165→      filterSpecs,
   166→      showInputFilter = false,
   167→      headerActions,
   168→      timezone = "UTC",
   169→      showTimeSpanSelector = true,
   170→      showRefresh = true,
   171→      showAutoRefresh = false,
   172→      chartSelectionFilterName,
   173→      dashboardId,
   174→      children,
   175→    },
   176→    ref
   177→  ) => {
   178→    const { connection } = useConnection();
   179→
   180→    // Generate default layouts for the layout provider
   181→    const defaultLayouts = useMemo(() => generateDefaultLayouts(panels), [panels]);
   182→
   183→    const inputFilterRef = useRef<HTMLInputElement>(null);
   184→    const filterRef = useRef<DashboardFilterComponent>(null);
   185→    const panelsRef = useRef<DashboardPanelContainerRef>(null);
   186→
   187→    useImperativeHandle(
   188→      ref,
   189→      () => ({
   190→        setSelectedTimeSpan: (timeSpan: TimeSpan) => {
   191→          filterRef.current?.setSelectedTimeSpan(timeSpan);
   192→        },
   193→        setFilter: (filterName: string, value: string) => {
   194→          filterRef.current?.setFilter(filterName, value);
   195→        },
   196→      }),
   197→      []
   198→    );
   199→
   200→    const defaultLoadFilterData = useCallback(
   201→      async (query: SQLQuery) => {
   202→        if (!connection) return [];
   203→        try {
   204→          // Cluster template replacement is now handled by connection.queryOnNode()
   205→          const sql = query.sql;
   206→
   207→          const { response } = connection.queryOnNode(sql, {
   208→            default_format: "JSONCompact",
   209→            ...query.params,
   210→          });
   211→
   212→          const apiResponse = await response;
   213→          return apiResponse.data
   214→            .json<JSONCompactFormatResponse>()
   215→            .data.map((row: unknown[]) => String(row[0]));
   216→        } catch (caught) {
   217→          console.error(caught);
   218→          return [];
   219→        }
   220→      },
   221→      [connection]
   222→    );
   223→
   224→    const refreshPanels = useCallback(
   225→      (timeSpan: TimeSpan, filter: SelectedFilter | undefined, inputFilter?: string) => {
   226→        const parts: string[] = [];
   227→        if (filter?.expr) {
   228→          parts.push(filter.expr);
   229→        }
   230→        if (inputFilter !== undefined) {
   231→          const value = inputFilter || inputFilterRef.current?.value || "";
   232→          if (value) {
   233→            parts.push(value);
   234→          }
   235→        } else {
   236→          const value = inputFilterRef.current?.value || "";
   237→          if (value) {
   238→            parts.push(value);
   239→          }
   240→        }
   241→        const filterExpression = parts.length > 0 ? parts.join(" AND ") : "1=1";
   242→        panelsRef.current?.refresh(timeSpan, filterExpression);
   243→      },
   244→      []
   245→    );
   246→
   247→    useEffect(() => {
   248→      const timer = setTimeout(() => {
   249→        if (filterRef.current) {
   250→          const timeSpan = filterRef.current.getSelectedTimeSpan();
   251→          const filter = filterRef.current.getSelectedFilter();
   252→          refreshPanels(timeSpan, filter);
   253→        }
   254→      }, 0);
   255→
   256→      return () => clearTimeout(timer);
   257→    }, [refreshPanels]);
   258→
   259→    const handleSelectionFilterChange = useCallback(
   260→      (filter: SelectedFilter) => {
   261→        const timeSpan = filterRef.current?.getSelectedTimeSpan();
   262→        if (!timeSpan) {
   263→          return;
   264→        }
   265→        refreshPanels(timeSpan, filter);
   266→      },
   267→      [refreshPanels]
   268→    );
   269→
   270→    const handleTimeSpanChange = useCallback(
   271→      (timeSpan: TimeSpan) => {
   272→        const filter = filterRef.current?.getSelectedFilter();
   273→        refreshPanels(timeSpan, filter);
   274→      },
   275→      [refreshPanels]
   276→    );
   277→
   278→    const handleInputFilterKeyDown = useCallback(
   279→      (event: React.KeyboardEvent<HTMLInputElement>) => {
   280→        if (event.key === "Enter") {
   281→          const inputFilterValue = inputFilterRef.current?.value || "";
   282→          const timeSpan = filterRef.current?.getSelectedTimeSpan();
   283→          const filter = filterRef.current?.getSelectedFilter();
   284→          if (timeSpan) {
   285→            refreshPanels(timeSpan, filter, inputFilterValue);
   286→          }
   287→        }
   288→      },
   289→      [refreshPanels]
   290→    );
   291→
   292→    const handleChartSelection = useCallback(
   293→      (timeSpan: TimeSpan, selection: { name: string; series: string; value: number }) => {
   294→        filterRef.current?.setSelectedTimeSpan(timeSpan);
   295→        if (chartSelectionFilterName && selection.series) {
   296→          filterRef.current?.setFilter(chartSelectionFilterName, selection.series);
   297→        }
   298→      },
   299→      [chartSelectionFilterName]
   300→    );
   301→
   302→    const hasFilters = filterSpecs && filterSpecs.length > 0;
   303→
   304→    const dashboardContent = (
   305→      <div className="flex flex-col h-full w-full overflow-hidden p-2 gap-2">
   306→        {dashboardId ? (
   307→          // With layout provider - use DashboardFilterWithReset for reset button
   308→          <DashboardFilterWithReset
   309→            filterRef={filterRef}
   310→            filterSpecs={hasFilters ? filterSpecs : []}
   311→            onFilterChange={hasFilters ? handleSelectionFilterChange : undefined}
   312→            onTimeSpanChange={handleTimeSpanChange}
   313→            onLoadSourceData={hasFilters ? defaultLoadFilterData : undefined}
   314→            timezone={timezone}
   315→            showTimeSpanSelector={showTimeSpanSelector}
   316→            showRefresh={showRefresh}
   317→            showAutoRefresh={showAutoRefresh}
   318→            headerActions={headerActions}
   319→          />
   320→        ) : (
   321→          // Without layout provider - regular filter without reset
   322→          <DashboardFilterComponent
   323→            ref={filterRef}
   324→            filterSpecs={hasFilters ? filterSpecs : []}
   325→            onFilterChange={hasFilters ? handleSelectionFilterChange : undefined}
   326→            onTimeSpanChange={handleTimeSpanChange}
   327→            onLoadSourceData={hasFilters ? defaultLoadFilterData : undefined}
   328→            timezone={timezone}
   329→            showTimeSpanSelector={showTimeSpanSelector}
   330→            showRefresh={showRefresh}
   331→            showAutoRefresh={showAutoRefresh}
   332→          >
   333→            {headerActions}
   334→          </DashboardFilterComponent>
   335→        )}
   336→
   337→        {showInputFilter && (
   338→          <div className="relative">
   339→            <Input
   340→              ref={inputFilterRef}
   341→              className="rounded-l rounded-r pl-2 h-8"
   342→              placeholder="Input filter expression, press ENTER to apply"
   343→              onKeyDown={handleInputFilterKeyDown}
   344→            />
   345→          </div>
   346→        )}
   347→
   348→        <div className="flex-1 min-h-0 overflow-hidden">
   349→          <DashboardPanelContainer
   350→            ref={panelsRef}
   351→            dashboard={panels}
   352→            dashboardId={dashboardId}
   353→            initialLoading={false}
   354→            onChartSelection={chartSelectionFilterName ? handleChartSelection : undefined}
   355→          >
   356→            {children}
   357→          </DashboardPanelContainer>
   358→        </div>
   359→      </div>
   360→    );
   361→
   362→    // Wrap with layout provider if dashboardId is provided
