function DashboardFilterWithReset({
  filterRef,
  filterSpecs,
  onFilterChange,
  onTimeSpanChange,
  onLoadSourceData,
  timezone,
  showTimeSpanSelector,
  showRefresh,
  showAutoRefresh,
  headerActions,
}: DashboardFilterWithResetProps) {
