    58→// Helper function to get gridPos from panel
    59→function getGridPos(panel: PanelDescriptor): GridPos {
    60→  if (panel.gridPos) {
    61→    return panel.gridPos;
    62→  }
    63→  console.warn(
    64→    `Panel "${panel.titleOption?.title ?? panel.type}" is missing gridPos. Using default.`
    65→  );
    66→  return { w: 24, h: 6 };
    67→}
    68→
    69→// Generate react-grid-layout layouts from panels
    70→function generateLayoutsFromPanels(panels: PanelDescriptor[]): ResponsiveLayouts {
    71→  const lg: LayoutItem[] = [];
    72→  const md: LayoutItem[] = [];
    73→  const sm: LayoutItem[] = [];
    74→
    75→  panels.forEach((panel, index) => {
    76→    const gridPos = getGridPos(panel);
    77→    const constraints = getPanelConstraints(panel.type);
    78→    const key = `panel-${index}`;
    79→
    80→    // Desktop layout (24 cols)
    81→    lg.push({
    82→      i: key,
    83→      x: gridPos.x ?? (index * 6) % 24,
    84→      y: gridPos.y ?? Math.floor((index * 6) / 24) * 4,
    85→      w: gridPos.w,
    86→      h: gridPos.h,
    87→      ...constraints,
    88→    });
    89→
    90→    // Tablet layout (6 cols)
    91→    const mdW = Math.max(constraints.minW, Math.round((gridPos.w / 24) * 6));
    92→    md.push({
    93→      i: key,
    94→      x: (index * 3) % 6,
    95→      y: Math.floor((index * 3) / 6) * 4,
    96→      w: Math.min(mdW, 6),
    97→      h: gridPos.h,
    98→      minW: Math.min(constraints.minW, 6),
    99→      minH: constraints.minH,
   100→      maxW: 6,
   101→      maxH: constraints.maxH,
   102→    });
   103→
   104→    // Mobile layout (1 col) - stack vertically
   105→    sm.push({
   106→      i: key,
   107→      x: 0,
   108→      y: index * 4,
   109→      w: 1,
   110→      h: gridPos.h,
   111→      minW: 1,
   112→      minH: constraints.minH,
   113→      maxW: 1,
   114→      maxH: constraints.maxH,
   115→      static: true,
   116→    });
   117→  });
   118→
   119→  return { lg, md, sm };
   120→}
   121→
   122→/**
   123→ * Dashboard section component containing a header and a grid of panels.
   124→ * Each section has its own ResponsiveGridLayout for independent drag/resize.
   125→ */
   126→export function DashboardSection({
   127→  dashboardId,
   128→  sectionIndex,
   129→  group,
   130→  panels,
   131→  isCollapsed,
   132→  onToggleCollapse,
   133→  onSubComponentUpdated,
   134→  globalPanelStartIndex,
   135→  initialTimeSpan,
   136→  initialFilterExpression,
   137→  initialLoading,
   138→  panelCollapseStates,
   139→  onPanelCollapsedChange,
   140→  onChartSelection,
   141→  showEditControls = false,
   142→  onRename,
   143→  onDelete,
   144→}: DashboardSectionProps) {
   145→  const { width, mounted, containerRef } = useContainerWidth();
   146→  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   147→
   148→  // Generate default layouts
   149→  const defaultLayouts = useMemo(
   150→    () => generateLayoutsFromPanels(panels),
   151→    [panels]
   152→  );
   153→
   154→  // Load saved layouts or use defaults
   155→  const [layouts, setLayouts] = useState<ResponsiveLayouts>(() => {
   156→    const saved = loadSectionLayout(dashboardId, sectionIndex);
   157→    return saved ?? defaultLayouts;
   158→  });
   159→
   160→  // Update layouts when panels change
   161→  useEffect(() => {
   162→    const saved = loadSectionLayout(dashboardId, sectionIndex);
   163→    setLayouts(saved ?? defaultLayouts);
   164→  }, [dashboardId, sectionIndex, defaultLayouts]);
   165→
   166→  // Handle layout change with debounced save
   167→  const onLayoutChange = useCallback(
   168→    (_currentLayout: Layout, allLayouts: ResponsiveLayouts) => {
   169→      setLayouts(allLayouts);
   170→
   171→      // Debounced save
   172→      if (saveTimeoutRef.current) {
   173→        clearTimeout(saveTimeoutRef.current);
   174→      }
   175→      saveTimeoutRef.current = setTimeout(() => {
