   627→/**
   628→ * Flatten panels from dashboard config (handles groups)
   629→ */
   630→function flattenPanels(
   631→  panels: (PanelDescriptor | DashboardGroup)[]
   632→): PanelDescriptor[] {
   633→  const result: PanelDescriptor[] = [];
   634→  for (const item of panels) {
   635→    if ("charts" in item && Array.isArray((item as DashboardGroup).charts)) {
   636→      result.push(...(item as DashboardGroup).charts);
   637→    } else {
   638→      result.push(item as PanelDescriptor);
   639→    }
   640→  }
   641→  return result;
   642→}
