   115→// Inner component to access layout context
   116→interface DashboardFilterWithResetProps {
   117→  filterRef: React.RefObject<DashboardFilterComponent | null>;
   118→  filterSpecs: FilterSpec[];
   119→  onFilterChange?: (filter: SelectedFilter) => void;
   120→  onTimeSpanChange?: (timeSpan: TimeSpan) => void;
   121→  onLoadSourceData?: (query: SQLQuery) => Promise<string[]>;
   122→  timezone?: string;
