   127→}
   128→
   129→function DashboardFilterWithReset({
   130→  filterRef,
   131→  filterSpecs,
   132→  onFilterChange,
   133→  onTimeSpanChange,
   134→  onLoadSourceData,
   135→  timezone,
   136→  showTimeSpanSelector,
   137→  showRefresh,
   138→  showAutoRefresh,
   139→  headerActions,
   140→}: DashboardFilterWithResetProps) {
   141→  const { resetLayout } = useDashboardLayout();
   142→
   143→  return (
   144→    <DashboardFilterComponent
   145→      ref={filterRef}
   146→      filterSpecs={filterSpecs}
   147→      onFilterChange={onFilterChange}
   148→      onTimeSpanChange={onTimeSpanChange}
   149→      onLoadSourceData={onLoadSourceData}
   150→      timezone={timezone}
   151→      showTimeSpanSelector={showTimeSpanSelector}
   152→      showRefresh={showRefresh}
   153→      showAutoRefresh={showAutoRefresh}
