   243→      },
   244→      []
   245→    );
   246→
   247→    useEffect(() => {
   248→      const timer = setTimeout(() => {
   249→        if (filterRef.current) {
   250→          const timeSpan = filterRef.current.getSelectedTimeSpan();
   251→          const filter = filterRef.current.getSelectedFilter();
   252→          refreshPanels(timeSpan, filter);
   253→        }
   254→      }, 0);
   255→
   256→      return () => clearTimeout(timer);
   257→    }, [refreshPanels]);
   258→
   259→    const handleSelectionFilterChange = useCallback(
   260→      (filter: SelectedFilter) => {
   261→        const timeSpan = filterRef.current?.getSelectedTimeSpan();
   262→        if (!timeSpan) {
   263→          return;
   264→        }
   265→        refreshPanels(timeSpan, filter);
   266→      },
   267→      [refreshPanels]
   268→    );
   269→
   270→    const handleTimeSpanChange = useCallback(
   271→      (timeSpan: TimeSpan) => {
   272→        const filter = filterRef.current?.getSelectedFilter();
   273→        refreshPanels(timeSpan, filter);
   274→      },
   275→      [refreshPanels]
   276→    );
   277→
   278→    const handleInputFilterKeyDown = useCallback(
   279→      (event: React.KeyboardEvent<HTMLInputElement>) => {
   280→        if (event.key === "Enter") {
   281→          const inputFilterValue = inputFilterRef.current?.value || "";
   282→          const timeSpan = filterRef.current?.getSelectedTimeSpan();
   283→          const filter = filterRef.current?.getSelectedFilter();
   284→          if (timeSpan) {
   285→            refreshPanels(timeSpan, filter, inputFilterValue);
   286→          }
   287→        }
   288→      },
   289→      [refreshPanels]
   290→    );
   291→
   292→    const handleChartSelection = useCallback(
   293→      (timeSpan: TimeSpan, selection: { name: string; series: string; value: number }) => {
   294→        filterRef.current?.setSelectedTimeSpan(timeSpan);
   295→        if (chartSelectionFilterName && selection.series) {
   296→          filterRef.current?.setFilter(chartSelectionFilterName, selection.series);
   297→        }
   298→      },
   299→      [chartSelectionFilterName]
   300→    );
   301→
   302→    const hasFilters = filterSpecs && filterSpecs.length > 0;
   303→
   304→    const dashboardContent = (
   305→      <div className="flex flex-col h-full w-full overflow-hidden p-2 gap-2">
   306→        {dashboardId ? (
   307→          // With layout provider - use DashboardFilterWithReset for reset button
   308→          <DashboardFilterWithReset
   309→            filterRef={filterRef}
   310→            filterSpecs={hasFilters ? filterSpecs : []}
   311→            onFilterChange={hasFilters ? handleSelectionFilterChange : undefined}
   312→            onTimeSpanChange={handleTimeSpanChange}
   313→            onLoadSourceData={hasFilters ? defaultLoadFilterData : undefined}
   314→            timezone={timezone}
   315→            showTimeSpanSelector={showTimeSpanSelector}
   316→            showRefresh={showRefresh}
   317→            showAutoRefresh={showAutoRefresh}
   318→            headerActions={headerActions}
   319→          />
   320→        ) : (
   321→          // Without layout provider - regular filter without reset
   322→          <DashboardFilterComponent
   323→            ref={filterRef}
   324→            filterSpecs={hasFilters ? filterSpecs : []}
   325→            onFilterChange={hasFilters ? handleSelectionFilterChange : undefined}
   326→            onTimeSpanChange={handleTimeSpanChange}
   327→            onLoadSourceData={hasFilters ? defaultLoadFilterData : undefined}
   328→            timezone={timezone}
   329→            showTimeSpanSelector={showTimeSpanSelector}
   330→            showRefresh={showRefresh}
   331→            showAutoRefresh={showAutoRefresh}
   332→          >
   333→            {headerActions}
   334→          </DashboardFilterComponent>
   335→        )}
   336→
   337→        {showInputFilter && (
   338→          <div className="relative">
   339→            <Input
   340→              ref={inputFilterRef}
   341→              className="rounded-l rounded-r pl-2 h-8"
   342→              placeholder="Input filter expression, press ENTER to apply"
   343→              onKeyDown={handleInputFilterKeyDown}
   344→            />
   345→          </div>
   346→        )}
   347→
   348→        <div className="flex-1 min-h-0 overflow-hidden">
   349→          <DashboardPanelContainer
   350→            ref={panelsRef}
   351→            dashboard={panels}
   352→            dashboardId={dashboardId}
   353→            initialLoading={false}
   354→            onChartSelection={chartSelectionFilterName ? handleChartSelection : undefined}
   355→          >
   356→            {children}
   357→          </DashboardPanelContainer>
   358→        </div>
   359→      </div>
   360→    );
   361→
   362→    // Wrap with layout provider if dashboardId is provided
   363→    if (dashboardId) {
   364→      return (
   365→        <DashboardLayoutProvider dashboardId={dashboardId} defaultLayouts={defaultLayouts}>
   366→          {dashboardContent}
   367→        </DashboardLayoutProvider>
   368→      );
   369→    }
   370→
   371→    return dashboardContent;
   372→  }
   373→);
   374→
   375→export default DashboardPage;
