    27→/**
    28→ * Interface for child components that can be refreshed by the dashboard.
    29→ * Children that implement this interface will be automatically refreshed
    30→ * when the dashboard is refreshed.
    31→ */
    32→export interface RefreshableChild {
    33→  refresh: (timeSpan?: TimeSpan, filterExpression?: string) => void;
    34→}
    35→
    36→/**
    37→ * Context for dashboard refresh registration.
    38→ * Child components can use the useDashboardRefresh hook to register
    39→ * themselves for automatic refresh when the dashboard refreshes.
    40→ */
    41→interface DashboardRefreshContextValue {
    42→  register: (child: RefreshableChild) => void;
    43→  unregister: (child: RefreshableChild) => void;
    44→}
    45→
    46→const DashboardRefreshContext = createContext<DashboardRefreshContextValue | null>(null);
    47→
    48→/**
    49→ * Hook for child components to register themselves for dashboard refresh.
    50→ * When the dashboard is refreshed, the provided refresh function will be called.
    51→ *
    52→ * @param refreshFn - Function to call when dashboard refreshes
    53→ *
    54→ * @example
    55→ * ```tsx
    56→ * const MyComponent = () => {
    57→ *   const fetchData = useCallback((timeSpan?: TimeSpan) => {
    58→ *     // fetch data...
    59→ *   }, []);
    60→ *
    61→ *   useDashboardRefresh(fetchData);
    62→ *
    63→ *   return <div>...</div>;
    64→ * };
    65→ * ```
    66→ */
    67→export function useDashboardRefresh(
    68→  refreshFn: (timeSpan?: TimeSpan, filterExpression?: string) => void
    69→) {
    70→  const ctx = useContext(DashboardRefreshContext);
    71→
    72→  useEffect(() => {
    73→    if (!ctx) return;
    74→
    75→    const child: RefreshableChild = { refresh: refreshFn };
    76→    ctx.register(child);
    77→
    78→    return () => {
    79→      ctx.unregister(child);
    80→    };
    81→  }, [ctx, refreshFn]);
    82→}
