   109→// Helper function to check if an item is a DashboardGroup
   110→function isDashboardGroup(item: unknown): item is DashboardGroup {
   111→  return (
   112→    typeof item === "object" &&
   113→    item !== null &&
   114→    "title" in item &&
   115→    "charts" in item &&
