   379→                  onChartSelection={onChartSelection}
   380→                  showEditControls={showSectionEditControls && section.group !== null}
   381→                  onRename={onSectionRename ? (title) => onSectionRename(section.sectionIndex, title) : undefined}
   382→                  onDelete={onSectionDelete ? () => onSectionDelete(section.sectionIndex) : undefined}
   383→                />
   384→              );
   385→            })}
   386→            {children}
   387→          </div>
   388→        </div>
   389→      </DashboardRefreshContext.Provider>
   390→    );
   391→  }
   392→);
   393→
   394→export default DashboardPanelContainer;
