    10→/**
    11→ * Represents a saved custom dashboard configuration
    12→ */
    13→export interface CustomDashboardConfig {
    14→  id: string;
    15→  name: string;
    16→  createdAt: number;
    17→  updatedAt: number;
    18→  filter: DashboardFilter;
    19→  filterSpecs: FilterSpec[];
    20→  panels: (PanelDescriptor | DashboardGroup)[];
    21→}
    22→
    23→/**
    24→ * Storage manager for custom dashboards.
    25→ * Persists dashboard configs to localStorage under "custom-dashboards" namespace.
    26→ */
    27→export class CustomDashboardStorage {
    28→  private static instance: CustomDashboardStorage;
    29→
    30→  static getInstance(): CustomDashboardStorage {
    31→    if (!this.instance) {
    32→      this.instance = new CustomDashboardStorage();
    33→    }
    34→    return this.instance;
    35→  }
    36→
    37→  private getStorage() {
    38→    return StorageManager.getInstance()
    39→      .getStorageProvider()
    40→      .subStorage("custom-dashboards")
    41→      .withCompression(true);
    42→  }
    43→
    44→  /**
    45→   * Get all saved dashboards (metadata only for listing)
    46→   */
    47→  getAll(): CustomDashboardConfig[] {
    48→    const stored = this.getStorage().getAsJSON<Record<string, CustomDashboardConfig>>(() => ({}));
    49→    return Object.values(stored).sort((a, b) => b.updatedAt - a.updatedAt);
    50→  }
    51→
    52→  /**
    53→   * Get a single dashboard by ID
    54→   */
    55→  get(id: string): CustomDashboardConfig | null {
    56→    const stored = this.getStorage().getAsJSON<Record<string, CustomDashboardConfig>>(() => ({}));
    57→    return stored[id] ?? null;
    58→  }
    59→
    60→  /**
    61→   * Save a dashboard (create or update)
    62→   */
    63→  save(config: CustomDashboardConfig): void {
    64→    const stored = this.getStorage().getAsJSON<Record<string, CustomDashboardConfig>>(() => ({}));
    65→    stored[config.id] = { ...config, updatedAt: Date.now() };
    66→    this.getStorage().setJSON(stored);
    67→  }
    68→
    69→  /**
    70→   * Delete a dashboard by ID
    71→   */
    72→  delete(id: string): void {
    73→    const stored = this.getStorage().getAsJSON<Record<string, CustomDashboardConfig>>(() => ({}));
    74→    delete stored[id];
    75→    this.getStorage().setJSON(stored);
    76→  }
    77→
    78→  /**
    79→   * Create a new empty dashboard with default structure
    80→   */
    81→  createNew(name: string): CustomDashboardConfig {
    82→    const now = Date.now();
    83→    const config: CustomDashboardConfig = {
    84→      id: `dashboard-${now}-${Math.random().toString(36).slice(2, 8)}`,
    85→      name,
    86→      createdAt: now,
    87→      updatedAt: now,
    88→      filter: {
    89→        showTimeSpanSelector: true,
    90→        showRefresh: true,
    91→      },
    92→      filterSpecs: [],
    93→      panels: [],
    94→    };
    95→    this.save(config);
    96→    return config;
    97→  }
    98→
    99→  /**
   100→   * Convert a CustomDashboardConfig to a Dashboard model for rendering
   101→   */
   102→  static toDashboard(config: CustomDashboardConfig): Dashboard {
   103→    return {
   104→      name: config.name,
   105→      version: 3,
   106→      filter: config.filter,
   107→      charts: config.panels,
   108→    };
   109→  }
   110→}
